// Hotpath benchmark for the monster WebGPU binding: reuse one texture/view/
// pipeline, then loop N frames of the per-frame CPU path (createCommandEncoder
// → beginRenderPass → setPipeline → draw → end → finish[record+replay] →
// submit). Measures the webgpu_host dispatch/record/replay/lock/alloc overhead.
const adapter = await navigator.gpu.requestAdapter();
const device = await adapter.requestDevice();
const W = 64, H = 64;
const tex = device.createTexture({
  size: { width: W, height: H }, format: 'rgba8unorm',
  usage: GPUTextureUsage.RENDER_ATTACHMENT | GPUTextureUsage.COPY_SRC,
});
const view = tex.createView();
const shader = device.createShaderModule({
  code: `
    @vertex fn vs(@builtin(vertex_index) i: u32) -> @builtin(position) vec4f {
      var p = array<vec2f,3>(vec2f(0.,0.7), vec2f(-0.7,-0.7), vec2f(0.7,-0.7));
      return vec4f(p[i], 0.0, 1.0);
    }
    @fragment fn fs() -> @location(0) vec4f { return vec4f(1.,0.,0.,1.); }
  `,
});
const pipeline = device.createRenderPipeline({
  layout: 'auto',
  vertex: { module: shader, entryPoint: 'vs' },
  fragment: { module: shader, entryPoint: 'fs', targets: [{ format: 'rgba8unorm' }] },
  primitive: { topology: 'triangle-list' },
});

const N = 1200;
const t0 = Date.now();
for (let i = 0; i < N; i++) {
  const enc = device.createCommandEncoder();
  const pass = enc.beginRenderPass({
    colorAttachments: [{ view, loadOp: 'clear', storeOp: 'store', clearValue: { r: 0, g: 0, b: 0, a: 1 } }],
  });
  pass.setPipeline(pipeline);
  pass.draw(3);
  pass.end();
  device.queue.submit([enc.finish()]);
}
const ms = Date.now() - t0;
console.log('__RESULT__ ' + JSON.stringify({ n: N, ms, perFrameUs: Math.round((ms * 1000) / N) }));
